# Generated by openai (o3)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        text(
            name: 'BUILD_COMMANDS',
            defaultValue: '',
            description: 'Enter build commands (one per line)'
        )
        text(
            name: 'TEST_COMMANDS',
            defaultValue: '',
            description: 'Enter test commands (one per line)'
        )
        text(
            name: 'DEPLOY_COMMANDS',
            defaultValue: '',
            description: 'Enter deployment commands (one per line)'
        )
    }

    stages {
        stage('Build') {
            when {
                expression { params.BUILD_COMMANDS?.trim() }
            }
            steps {
                sh """
                    #!/bin/bash
                    set -e
                    ${params.BUILD_COMMANDS}
                """
            }
        }

        stage('Test') {
            when {
                expression { params.TEST_COMMANDS?.trim() }
            }
            steps {
                sh """
                    #!/bin/bash
                    set -e
                    ${params.TEST_COMMANDS}
                """
            }
        }

        stage('Deploy') {
            when {
                expression { params.DEPLOY_COMMANDS?.trim() }
            }
            steps {
                sh """
                    #!/bin/bash
                    set -e
                    ${params.DEPLOY_COMMANDS}
                """
            }
        }
    }

    post {
        always {
            archiveArtifacts artifacts: '**/*', allowEmptyArchive: true
        }
    }
}